import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Create Web Links","description":"","frontmatter":{"title":"Create Web Links","slug":"create-web-links"},"headers":[],"relativePath":"marketer-hub/create-web-links.md","filePath":"marketer-hub/create-web-links.md"}'),n={name:"marketer-hub/create-web-links.md"};function i(s,e,l,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Attention</p><p><a href="https://help.branch.io/docs/create-web-links-1" target="_blank" rel="noreferrer">New Branch</a> is now available for some users, your experience may differ.</p></div><div class="info custom-block"><p class="custom-block-title">Note</p><p>The information in this article is relevant to the Activation product. If you want information about web link creation for the Engagement product, read our <a href="./legacy-link-creation.html">Legacy Web Short Link Creation</a> article.</p></div><p>Web links are Branch Links that take your users to web destinations. There are four primary methods you can use to create web links:</p><ul><li>Method 1: Create web in the Branch Dashboard</li><li>Method 2: Create bulk web Short Links in the Branch Dashboard</li><li>Method 3: Create Short Links in the Branch Slack App</li><li>Method 4: Create web links through the Deep Linking API</li></ul><h3 id="how-branch-links-work" tabindex="-1">How Branch Links work <a class="header-anchor" href="#how-branch-links-work" aria-label="Permalink to &quot;How Branch Links work&quot;">​</a></h3><p>Web Links are web-only Short Links that work everywhere. App links are deep links that take users to specific pages in your app. Web and app links look the same (yourbrand.com/slug or yourbrand.app.link/slug) depending on if you choose to use a custom domain or a Branch-provided app.link domain.</p><h4 id="expected-behavior-for-web-links" tabindex="-1">Expected behavior for web links <a class="header-anchor" href="#expected-behavior-for-web-links" aria-label="Permalink to &quot;Expected behavior for web links&quot;">​</a></h4><p>If your end user does <strong>not</strong> have your app installed, or if you don’t have an app, the link will open in their default web browser. If they do have your app downloaded, the link will open in your app through an in-app web view.</p><h4 id="expected-behavior-for-app-links" tabindex="-1">Expected behavior for app links <a class="header-anchor" href="#expected-behavior-for-app-links" aria-label="Permalink to &quot;Expected behavior for app links&quot;">​</a></h4><p>If your end user has your app installed, the App Link will deep link to the specific app page you’ve chosen. If they do <strong>not</strong> have your app installed, they will taken to the redirect destination for non-app users which can be configured as a web page, a Branch Deepview, or the app store listing to download the app.</p><p>Read our <a href="./create-app-links.html">Create App Links</a> article to learn more about app links.</p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>You can set up a custom domain in the Branch Dashboard or you can use the Branch-provided app.link domain. If you want in-app web views to work, you must have the latest version of the Branch SDK installed.</p><h3 id="set-up-a-custom-domain-optional" tabindex="-1">Set up a custom domain (optional) <a class="header-anchor" href="#set-up-a-custom-domain-optional" aria-label="Permalink to &quot;Set up a custom domain (optional)&quot;">​</a></h3><p>You can set up a custom domain (for example, link.yourbrand.com) in the Branch Dashboard. Visit our <a href="./basic-link-configuration.html#5-link-domain">Basic Link Configuration</a> guide to learn how.</p><p>After you set up your custom domain, you can use it to create branded web Short Links.</p><h3 id="set-up-app-integration-optional" tabindex="-1">Set up app integration (optional) <a class="header-anchor" href="#set-up-app-integration-optional" aria-label="Permalink to &quot;Set up app integration (optional)&quot;">​</a></h3><p>You must have the latest version of the Branch SDK (latest update May 15, 2025) installed for in-app web views to work.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you don’t want to show an in-app web view for web Short Links, you can skip this setup.</p></div><p>Read the following articles to learn more:</p><ul><li><a href="https://help.branch.io/developers-hub/docs/native-sdks-overview" target="_blank" rel="noreferrer">Branch SDK Overview</a></li><li><a href="https://help.branch.io/developers-hub/docs/ios-sdk-overview" target="_blank" rel="noreferrer">Branch iOS SDK Overview</a></li><li><a href="https://help.branch.io/developers-hub/docs/android-sdk-overview" target="_blank" rel="noreferrer">Branch Android SDK Overview</a></li></ul><h2 id="create-web-links" tabindex="-1">Create web links <a class="header-anchor" href="#create-web-links" aria-label="Permalink to &quot;Create web links&quot;">​</a></h2><h3 id="method-1-short-links-in-the-branch-dashboard" tabindex="-1">Method 1: Short Links in the Branch Dashboard <a class="header-anchor" href="#method-1-short-links-in-the-branch-dashboard" aria-label="Permalink to &quot;Method 1: Short Links in the Branch Dashboard&quot;">​</a></h3><p>You can create individual Short Links in the Branch Dashboard.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>You can quickly access the <strong>Create Short Links</strong> page by entering <a href="https://deeplink.new" target="_blank" rel="noreferrer">deeplink.new</a> in your browser.</p></div><h4 id="step-1-start-creating-link" tabindex="-1">Step 1: Start creating link <a class="header-anchor" href="#step-1-start-creating-link" aria-label="Permalink to &quot;Step 1: Start creating link&quot;">​</a></h4><p>Complete the following steps to start creating a link:</p><ol><li>In the Branch Dashboard, select the <strong>Create</strong> button in the top-right corner of the page.</li><li>Select <strong>Link</strong>.</li><li>Select <strong>Short Link</strong>. The <strong>Create Short Link</strong> page will open.</li></ol><h4 id="step-2-define-your-web-short-link" tabindex="-1">Step 2: Define your web Short Link <a class="header-anchor" href="#step-2-define-your-web-short-link" aria-label="Permalink to &quot;Step 2: Define your web Short Link&quot;">​</a></h4><p>Complete the following steps to define your link:</p><ol><li>Enter your link title in the <strong>Link Title</strong> text field. We recommend standardizing your link names to make them easily searchable.</li><li>Select <strong>Web</strong>.</li><li>Enter the long URL that you want to shorten in the <strong>Destination URL</strong> text field. This is where your Short Link will redirect to.</li><li>(Optional) Select the domain that you want this link to use from the <strong>Link Domain</strong> drop-down menu.</li><li>(Optional) Enter a custom link alias (slug/back-half) in the Link Alias text field. You won’t be able to change this once you select <strong>Create Link</strong>.</li></ol><h4 id="step-3-add-analytics-tags-optional" tabindex="-1">Step 3: Add analytics tags (optional) <a class="header-anchor" href="#step-3-add-analytics-tags-optional" aria-label="Permalink to &quot;Step 3: Add analytics tags (optional)&quot;">​</a></h4><p>Add analytics tags to your link to sort and compare performance with your other links.</p><p>You can add analytics tags in two ways in the <strong>Analytics Tags</strong> section:</p><ul><li>Use the drop-downs to select analytics tags that you’ve used in the last 30 days.</li><li>Enter new analytics tags in the text fields and select <strong>Create [ANALYTICS TAG]</strong> to create a new tag.</li></ul><details><summary>Available tags</summary><p>You can add the following analytics tags to your link:</p><ul><li><strong>Feature</strong>: Should describe the action or product where this link is placed. For UTM, this is typically utm_medium.</li><li><strong>Channel</strong>: Should describe the platform or source from which you are expecting users to click this link. For UTM, this is typically utm_source.</li><li><strong>Campaign</strong>: This can very, but it should describe the theme of the link. For UTM, this is typically utm_campaign.</li><li><strong>Tags</strong>: Tags are a free-form list of meaningful labels that can be used as filters in the Short Links table. Use them to keep your analytics organized.</li></ul></details><div class="info custom-block"><p class="custom-block-title">Note</p><p>For a tag from a previous Short Link to appear in the drop-down list, the previously created Short Link must be published with at least one click on it.</p></div><h4 id="step-4-add-link-data-optional" tabindex="-1">Step 4: Add link data (optional) <a class="header-anchor" href="#step-4-add-link-data-optional" aria-label="Permalink to &quot;Step 4: Add link data (optional)&quot;">​</a></h4><p>Add any custom link settings, custom analytics tags, or custom redirect logic. You can view <a href="https://help.branch.io/docs/creating-a-deep-link#custom-data" target="_blank" rel="noreferrer">custom data options</a> and <a href="https://help.branch.io/docs/creating-a-deep-link#keys-for-reporting-analytics" target="_blank" rel="noreferrer">advanced analytics tag options</a> in our <a href="./creating-a-deep-link.html">Create Deep Links</a> article.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>You can type into the text field to add link data options.</p></div><details><summary>Advanced link configuration for web links</summary><table tabindex="0"><thead><tr><th>Key</th><th>Usage</th></tr></thead><tbody><tr><td><code>$fallback_url_xx</code></td><td>Change the redirect endpoint for all platforms based on a <a href="https://www.iso.org/obp/ui/#search" target="_blank" rel="noreferrer">lower-case Alpha-2 country code</a>. For example, <code>$fallback_url_de=&quot;...&quot;</code> would redirect Germany deep link clicks. You should also set <code>$fallback_url</code> to act as the global redirect in addition to the country-specific ones. WARNING: platform specific redirects (like $ios_url or $desktop_url) are set, they will override the country-specific redirect. Thus, the recommendation is to only use $fallback_url_xx for the country specific redirects and $fallback_url to catch all other users.</td></tr><tr><td><code>$exp_date</code></td><td>Expiry date for the content and any associated link data. Represented as UTC epoch milli second. The maximum date this can be set is 31 days in the future.</td></tr><tr><td><code>$desktop_url</code></td><td>Redirect URL for desktop devices - mobile users will default to the app store.</td></tr><tr><td><code>$ios_url</code></td><td>Change the redirect endpoint for iOS App Store page for your app (set in Link Settings).</td></tr><tr><td><code>$ios_url_xx</code></td><td>Change the redirect endpoint for iOS based on a <a href="https://www.iso.org/obp/ui/#search" target="_blank" rel="noreferrer">lower-case Alpha-2 country code</a>. For example, <code>$ios_url_de=&quot;...&quot;</code> would redirect Germany deep link clicks. You should also set <code>$ios_url</code> to act as the global redirect in addition to the country-specific ones.</td></tr><tr><td><code>$android_url</code></td><td>Change the redirect endpoint for Android Play Store page for your app (set in Link Settings).</td></tr><tr><td><code>$android_url_xx</code></td><td>Change the redirect endpoint for Android based on a <a href="https://www.iso.org/obp/ui/#search" target="_blank" rel="noreferrer">lower-case Alpha-2 country code</a>. For example, <code>$android_url_de=&quot;...&quot;</code> would redirect Germany deep link clicks. You should also set <code>$android_url</code> to act as the global redirect in addition to the country-specific ones.</td></tr><tr><td><code>$ipad_url</code></td><td>Change the redirect endpoint for iPads <code>$ios_url</code> value</td></tr><tr><td><code>$samsung_url</code></td><td>Redirect to Samsung Galaxy Store on Samsung devices. Only link level control. Format should be <code>http://www.samsungapps.com/appquery/appDetail.as?appId=YOUR.PACKAGE.NAME</code></td></tr><tr><td><code>$windows_phone_url</code></td><td>Change the redirect endpoint for Windows OS Windows Phone default URL (set in Link Settings).</td></tr><tr><td><code>$blackberry_url</code></td><td>Change the redirect endpoint for Blackberry OS BlackBerry default URL (set in Link Settings).</td></tr><tr><td><code>$fire_url</code></td><td>Change the redirect endpoint for Amazon Fire OS Fire default URL (set in Link Settings).</td></tr><tr><td><code>$ios_wechat_url</code></td><td>Change the redirect endpoint for WeChat on iOS devices <code>$ios_url</code> value.</td></tr><tr><td><code>$android_wechat_url</code></td><td>Change the redirect endpoint for WeChat on Android devices <code>$android_url</code> value.</td></tr></tbody></table></details><h4 id="step-5-customize-qr-code-optional" tabindex="-1">Step 5: Customize QR code (optional) <a class="header-anchor" href="#step-5-customize-qr-code-optional" aria-label="Permalink to &quot;Step 5: Customize QR code (optional)&quot;">​</a></h4><p>Customize the QR code for this link by selecting the pencil icon above the <strong>QR Preview</strong> section. Learn more in our <a href="./qr-codes-builder.html">Customize QR Codes</a> article.</p><p>Select <strong>Done</strong> to save your customizations.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Switching between web-only and app routing may change the link URL depending on your package and domain configuration. If this link will be used in print, finalize your routing strategy before distribution. See <a href="https://help.branch.io/marketer-hub/docs/create-qr-codes" target="_blank" rel="noreferrer">Create QR Codes</a> for details.</p></div><h4 id="step-6-customize-link-preview-optional" tabindex="-1">Step 6: Customize link preview (Optional) <a class="header-anchor" href="#step-6-customize-link-preview-optional" aria-label="Permalink to &quot;Step 6: Customize link preview (Optional)&quot;">​</a></h4><p>Customize the link preview for this link by selecting the pencil icon above the <strong>Link Preview</strong> section. You can customize the title, description, and background image. This is what your link will look like on social media platforms, messaging apps, and anywhere that supports link previews.</p><p>Select <strong>Done</strong> to save your customizations.</p><h4 id="step-7-finish-creating-your-link" tabindex="-1">Step 7: Finish creating your link <a class="header-anchor" href="#step-7-finish-creating-your-link" aria-label="Permalink to &quot;Step 7: Finish creating your link&quot;">​</a></h4><p>Select <strong>Create Link</strong> to finish creating your link.</p><h3 id="method-2-bulk-short-links-in-the-branch-dashboard" tabindex="-1">Method 2: Bulk Short Links in the Branch Dashboard <a class="header-anchor" href="#method-2-bulk-short-links-in-the-branch-dashboard" aria-label="Permalink to &quot;Method 2: Bulk Short Links in the Branch Dashboard&quot;">​</a></h3><p>You can create web Short Links in bulk in the Branch Dashboard.</p><p>Complete the following steps to create web Short Links in bulk:</p><ol><li><p>In the Branch Dashboard, select <strong>LinkHub</strong>.</p></li><li><p>Select <strong>Create Bulk Links</strong> in the top-right corner.</p></li><li><p>Select <strong>Short Links</strong>.</p></li><li><p>Select whether you want to create your Short Links with an existing template or a CSV. You can download a sample CSV to get started by selecting <strong>Via CSV Upload</strong> &gt; <strong>sample CSV file</strong>.</p></li><li><p>Add the relevant information for your links. Open the accordion below to view more information about link information. Make sure the <strong>Web Only</strong> checkbox is selected for your links to be web links.</p><p><strong>Expand to view available fields</strong></p><table tabindex="0"><thead><tr><th><strong>Required?</strong></th><th><strong>Field</strong></th><th><strong>Description</strong></th></tr></thead><tbody><tr><td><strong>Yes</strong></td><td><strong>Link Title</strong></td><td><strong>Link title is the name of the Short Link that will be displayed and be searchable in the Short Links table. Try making it descriptive and memorable for you and your team.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Link Alias</strong></td><td><strong>Link alias (link slug) is the part of the link after the domain. For example, in “branch.app.link/example”, “example” is the alias. The alias should ideally describe the landing page of the link. This can&#39;t be edited once the link has been created. If this field is left blank, Branch will generate a unique link hash for you.</strong></td></tr><tr><td><strong>Yes</strong></td><td><strong>Feature</strong></td><td><strong>Feature should describe the action or product where this link is placed.In the UTM world, this is typically utm_medium.</strong></td></tr><tr><td><strong>Yes</strong></td><td><strong>Channel</strong></td><td><strong>Channel should describe the platform or source from which you are expecting users to click this link. In the UTM world, this is typically utm_source.</strong></td></tr><tr><td><strong>Yes</strong></td><td><strong>Campaign (utm_campaign)</strong></td><td><strong>Campaign varies from company to company, but it should describe the theme of the link. In the UTM world, this is typically utm_campaign.</strong></td></tr><tr><td><strong>Yes</strong></td><td><strong>Original Web URL</strong></td><td><strong>Branch can fetch and fill data for a link from a page on your website, including open graph tags and other metadata. You&#39;ll see this metadata appear in the optional sections later in this creator. This helps reduce the number of steps for you to create a well-configured link.</strong></td></tr><tr><td><strong>Yes</strong></td><td><strong>Custom Key: $canonical_url</strong></td><td><strong>N/A</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Tags</strong></td><td><strong>Tags are a free-form list of meaningful labels that can be used as filters in the Short Links table. Use them to keep your analytics organized.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Social Media Title</strong></td><td><strong>Title that will appear in this link’s social media preview.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Social Media Description</strong></td><td><strong>Description that will appear in this link’s social media preview.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Social Media Image URL</strong></td><td><strong>Note that your image may be cropped and aligned differently depending on the social platform.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>iOS Default Redirect</strong></td><td><strong>Can’t be changed when creating links in bulk.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Android Default Redirect</strong></td><td><strong>Can’t be changed when creating links in bulk.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Desktop Default Redirect</strong></td><td><strong>Can’t be changed when creating links in bulk.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Web Only</strong></td><td><strong>Column edit is restricted as per the Link Template settings. To change the setting please edit the Link Template.</strong></td></tr></tbody></table></li><li><p>Select <strong>Create Links</strong> or <strong>Publish Bulk Links</strong> depending on which method you chose.</p></li></ol><h3 id="method-3-short-links-in-the-branch-slack-app" tabindex="-1">Method 3: Short Links in the Branch Slack App <a class="header-anchor" href="#method-3-short-links-in-the-branch-slack-app" aria-label="Permalink to &quot;Method 3: Short Links in the Branch Slack App&quot;">​</a></h3><p>You can create web Short Links using the Branch Slack App. Read our <a href="./branch-slack-app.html">Branch Slack App</a> article to learn more.</p><h3 id="method-4-web-links-through-the-deep-linking-api" tabindex="-1">Method 4: Web links through the Deep Linking API <a class="header-anchor" href="#method-4-web-links-through-the-deep-linking-api" aria-label="Permalink to &quot;Method 4: Web links through the Deep Linking API&quot;">​</a></h3><p>The <a href="https://help.branch.io/apidocs/deep-linking-api" target="_blank" rel="noreferrer">Deep Linking API</a> is included in <a href="https://help.branch.io/docs/packaging#engagement-essentials-tier" target="_blank" rel="noreferrer">Engagement Essentials</a> and <a href="https://help.branch.io/docs/packaging#activation-essentials-tier" target="_blank" rel="noreferrer">Activation Essentials</a>. You can use it to create both web and app Short Links.</p><h2 id="view-and-manage-links" tabindex="-1">View and manage links <a class="header-anchor" href="#view-and-manage-links" aria-label="Permalink to &quot;View and manage links&quot;">​</a></h2><p>You can use LinkHub to manage and view your Short Links. Learn more in our <a href="./linkhub.html">LinkHub</a> article. With Activation you’ll see separate <strong>Web Short Links</strong> and <strong>App Short Links</strong> tabs.</p><p>You can also view Web Short Links on the <strong>Overview</strong> page in the Branch Dashboard on the <strong>All Data</strong> and <strong>Short Links</strong> tabs.</p><h2 id="analyze-link-performance" tabindex="-1">Analyze link performance <a class="header-anchor" href="#analyze-link-performance" aria-label="Permalink to &quot;Analyze link performance&quot;">​</a></h2><h4 id="linkhub" tabindex="-1">LinkHub <a class="header-anchor" href="#linkhub" aria-label="Permalink to &quot;LinkHub&quot;">​</a></h4><p>In LinkHub, you can view how many clicks your links have received. Select the <strong>Clicks</strong> column in the table to sort by most clicks or least clicks. You can learn more in our <a href="./linkhub.html">LinkHub</a> article.</p><h4 id="overview-page" tabindex="-1">Overview page <a class="header-anchor" href="#overview-page" aria-label="Permalink to &quot;Overview page&quot;">​</a></h4><p>On the <strong>Overview</strong> page, use the <strong>Summary</strong> or <strong>Sources</strong> tabs to view relevant analytics for your links. Read our <a href="./branch-summary-page.html">Overview Page</a> article to learn more about comparing and filtering results.</p><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>Why are some Short Link thumbnails not shown in WhatsApp?</summary><p>The most common issue with Short Links not rendering thumbnail previews in WhatsApp is the image file size being too large. Although Facebook supports the display of Open Graph images <a href="https://developers.facebook.com/docs/sharing/webmasters/images/#images-in-link-shares" target="_blank" rel="noreferrer">up to 8 MB</a> in size, their WhatsApp product appears to have different, undocumented size limitations. We&#39;ve seen that WhatsApp generally displays thumbnail previews for images up to 300 KB.</p><p>If your image file is larger than 300 KB, try reducing the image file size by adjusting your image dimensions or compression settings.</p></details><details><summary>Can I see the stats for links created using the API or SDK in Branch?</summary><p>Viewing Individual Link level stats for API/SDK created links is currently not available. Aggregate Stats can be observed in Branch by filtering with link analytics tags.</p></details><details><summary>Why aren’t my Short Links showing up in Branch?</summary><p>The Short Links section in Branch shows links that were generated in Branch. API/SDK-generated links are not visible in Branch.</p><p>If the Short Link you are looking for does not appear in Branch, it’s possible that the link wasn’t fetched in the first search. You will have to click on “Load More” at the bottom of the page, you should then be able to see the link pop up if it still exists.</p></details><details><summary>Why is my Short Link redirection not working as expected?</summary><p>If the Short Link redirection is not working as expected, we recommend trying to debug the link first to see if it is set up correctly.</p><ol><li>To debug a Short Link, you can go to <strong>Short Link</strong> &gt; <strong>Select a link</strong> and click on the ellipses, then click <strong>Debug</strong>.</li><li>On the Debug page, check the <strong>Link Details</strong> and the <strong>Link Routing Debugger</strong> section.</li></ol><p>You can also debug a link by adding debug=1 at the end of the link as a query parameter. For example: <a href="https://branchster.app.link/share-with-friends7**?debug=1" target="_blank" rel="noreferrer">https://branchster.app.link/share-with-friends7**?debug=1</a></p></details><details><summary>How can I create a Short Link for Snapchat?</summary><p>Snap won&#39;t let you attach redirecting links to stories. The following workaround disables the redirects until you get the link attached, and then re-enables them after you create your story.</p><ol><li><p>Create your Short Link to be attached to your Snap story.</p></li><li><p>On the Configure Options section, do the following:</p><ol><li>Add the key $always_deeplink, and the value of false in the <strong>Deep Linking</strong> tab.</li><li>Enable a Deepview on the iOS platform in the <strong>Redirects</strong> tab.</li></ol></li><li><p>Attach this link to your Snap story.</p></li><li><p>Come back and edit the Short Link to:</p><ol><li>Delete the $always_deeplink key/value from the <strong>Deep Linking</strong> tab.</li><li>Remove the Deepview on iOS in the <strong>Redirects</strong> tab.</li></ol></li></ol></details><details><summary>Does a Branch-generated QR code have an expiration date?</summary><p>No, QR codes do not have an expiration date. The QR code has a Short Link behind it. As long as the Short Link is active, the QR code will continue to work. Short Links will always be active if not deleted or archived. However, if you change the link domain (***.<a href="http://app.link" target="_blank" rel="noreferrer">app.link</a>) of your Branch app, all Short Links and the QR codes created with the old domain will stop working.</p></details><details><summary>Why do I have to click on &#39;Load More&#39; to find my link when searching Short Links?</summary><p>The dashboard only loads the last 500 Short Links. If the link that you are searching for is not part of these 500 links, click &#39;Load More&#39; in order to continue searching.</p><p>You can also load the Short Link directly, by going to the following URL with the corresponding Short Link ID appended to the end.</p><p><a href="https://dashboard.branch.io/quick-links/qlc/config/" target="_blank" rel="noreferrer">https://dashboard.branch.io/quick-links/qlc/config/</a>[Short Link ID]</p></details><details><summary>Are the number of &#39;Opens&#39; included in the number of &#39;Installs&#39; reported in Branch?</summary><p>Opens are not included in installs. If a user who already has the app clicks on the link and opens the app, it is counted as an open. If the app is not installed, the user is taken to the app/play store to install the app. The first time they open the app after the install is counted as an install.</p></details><details><summary>Can updating the Social Media Descriptors affect an app’s ranking in app store searches?</summary><p>Updating the Social Media descriptors will only change the Image and description associated with the link, will not have any impact on the app&#39;s search ranking.</p><p>These values will be updated next time the link is scrapped by the respective platform.</p></details><details><summary>Does Branch over-write UTM parameters if they are already detected in a link?</summary><p>When you use Branch links for redirecting users to a web URL, Branch automatically passes through any values from the following Branch link analytics tags as UTM parameters [~campaign -&gt; utm_campaign, ~channel -&gt; utm_source, ~feature -&gt; utm_medium]. However, If these UTM parameters are already detected on the URLs being redirected to, Branch will not overwrite them unless you have disabled the &#39;Analytics mapping with UTM&#39; setting on your Branch dashboard, which is already enabled by default</p><p>To view this setting, navigate to <strong>Configuration</strong> &gt; <strong>Advanced Settings</strong> in Branch.</p></details><details><summary>How long does it take for new images to appear on social media preview once updated?</summary><p>Branch will update the link &#39;og&#39; parameters immediately after it is updated. However how the social media descriptors show up on a platform are controlled by the platform. Different platforms handle these links in different ways, the platform might scrape the link everytime it is shared and the image might get refreshed immediately. However in most cases the link is not scraped regularly hence you might see a time lag before the image is updated for the link. If you are sharing on Facebook owned platforms you can manually scrape the link by visiting <a href="https://developers.facebook.com/tools/debug/" target="_blank" rel="noreferrer">https://developers.facebook.com/tools/debug/</a></p><p>Please note that the <code>$og_image_url</code> social preview feature is reserved for paid Branch accounts with a dedicated contract. If you do not have a paid Branch account, you will not see this feature in Branch.</p></details><details><summary>Why am I unable to find my link in the Short Links Section?</summary><p>Branch only shows you the last 500 Short Links created. You can access the next 500 Short Links by clicking on <strong>Load More</strong> at the end of the list.</p><p>Alternatively you can directly open the Short Link by navigating to the Short Link appended by the following parameters on a browser where you are signed in to Branch.</p><ul><li>To edit the link append ?edit=1</li><li>To view stats append ?stats=1</li><li>To debug the link append ?debug=1</li></ul><p>For example, if you want to edit <a href="https://example.app.link/testlink" target="_blank" rel="noreferrer">https://example.app.link/testlink</a>, try opening <a href="https://example.app.link/testlink?edit=1" target="_blank" rel="noreferrer">https://example.app.link/testlink?edit=1</a>.</p></details><details><summary>How are Short Links different from Ad Links?</summary><h4 id="functionality" tabindex="-1">Functionality <a class="header-anchor" href="#functionality" aria-label="Permalink to &quot;Functionality&quot;">​</a></h4><p>Functionally, Short Links and Ad Links work the same -- they both attribute in the same fashion (outside of the iOS ATT restrictions -- Short Links are “owned” links so these can still attribute downstream data) and route users in the same way to the destinations set up on the links.</p><p><a href="https://help.branch.io/v1/docs/ad-links" target="_blank" rel="noreferrer">Ad Links</a> are primarily designed for working with ad partners, so they’ll include a $3p value that designates the specific ad partner, and for integrated partners, they’ll include a much longer URL string that includes macros for the partner to pass through dynamic values like campaign name, etc. Additionally, Ad Links will automatically implement ATT-compliant behavior on iOS. <a href="https://help.branch.io/faq/docs/how-do-we-configure-a-non-ads-link-to-use-branchs-att-compliant-behavior" target="_blank" rel="noreferrer">This is not the case for Short Links</a>.</p><p><a href="https://help.branch.io/v1/docs/create-quick-links" target="_blank" rel="noreferrer">Short Links</a> are for “owned” placements (non-paid-ads use cases in general) and cases where the link may be visible, and Ad Links are designed for paid ads where users aren’t expected to see the link itself as well as where dynamic data is expected to be passed.</p><p>For a list of what Branch Link to use for a specific use case, see below:</p><table tabindex="0"><thead><tr><th>Branch Link</th><th>Use Cases</th></tr></thead><tbody><tr><td>Short Link</td><td>- Quick QR Code generator (via Branch Dashboard). - Custom Vanity/Alias Link. ex. <code>branchster.app.link/discount2022``df</code></td></tr><tr><td>Ad Link</td><td>Ad Partner Campaign. ex. Facebook Ad Link: <code>https://branchster.app.link/J9g9yuoTPqb?%243p=a_facebook&amp;%24deeplink_no_attribution=true</code></td></tr></tbody></table><h4 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h4><p>Branch Ad Link creation is included in our Performance Essentials <a href="https://help.branch.io/docs/products" target="_blank" rel="noreferrer">product tier</a>, while access to the <a href="https://help.branch.io/v1-api/apidocs/quick-links-api" target="_blank" rel="noreferrer">Short Links API</a> is limited to Engagement Pro customers.</p></details><details><summary>Expand to view available fields</summary><table tabindex="0"><thead><tr><th><strong>Required?</strong></th><th><strong>Field</strong></th><th><strong>Description</strong></th></tr></thead><tbody><tr><td><strong>Yes</strong></td><td><strong>Link Title</strong></td><td><strong>Link title is the name of the Short Link that will be displayed and be searchable in the Short Links table. Try making it descriptive and memorable for you and your team.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Link Alias</strong></td><td><strong>Link alias (link slug) is the part of the link after the domain. For example, in “branch.app.link/example”, “example” is the alias. The alias should ideally describe the landing page of the link. This can&#39;t be edited once the link has been created. If this field is left blank, Branch will generate a unique link hash for you.</strong></td></tr><tr><td><strong>Yes</strong></td><td><strong>Feature</strong></td><td><strong>Feature should describe the action or product where this link is placed.In the UTM world, this is typically utm_medium.</strong></td></tr><tr><td><strong>Yes</strong></td><td><strong>Channel</strong></td><td><strong>Channel should describe the platform or source from which you are expecting users to click this link. In the UTM world, this is typically utm_source.</strong></td></tr><tr><td><strong>Yes</strong></td><td><strong>Campaign (utm_campaign)</strong></td><td><strong>Campaign varies from company to company, but it should describe the theme of the link. In the UTM world, this is typically utm_campaign.</strong></td></tr><tr><td><strong>Yes</strong></td><td><strong>Original Web URL</strong></td><td><strong>Branch can fetch and fill data for a link from a page on your website, including open graph tags and other metadata. You&#39;ll see this metadata appear in the optional sections later in this creator. This helps reduce the number of steps for you to create a well-configured link.</strong></td></tr><tr><td><strong>Yes</strong></td><td><strong>Custom Key: $canonical_url</strong></td><td><strong>N/A</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Tags</strong></td><td><strong>Tags are a free-form list of meaningful labels that can be used as filters in the Short Links table. Use them to keep your analytics organized.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Social Media Title</strong></td><td><strong>Title that will appear in this link’s social media preview.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Social Media Description</strong></td><td><strong>Description that will appear in this link’s social media preview.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Social Media Image URL</strong></td><td><strong>Note that your image may be cropped and aligned differently depending on the social platform.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>iOS Default Redirect</strong></td><td><strong>Can’t be changed when creating links in bulk.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Android Default Redirect</strong></td><td><strong>Can’t be changed when creating links in bulk.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Desktop Default Redirect</strong></td><td><strong>Can’t be changed when creating links in bulk.</strong></td></tr><tr><td><strong>No</strong></td><td><strong>Web Only</strong></td><td><strong>Column edit is restricted as per the Link Template settings. To change the setting please edit the Link Template.</strong></td></tr></tbody></table></details>',82)])])}const u=t(n,[["render",i]]);export{g as __pageData,u as default};
